<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>Personal Expense Tracker</title>
    <style>
        body { font-family: sans-serif; margin: 20px; }
        table { width: 100%; border-collapse: collapse; margin-top: 20px; }
        th, td { padding: 8px; border: 1px solid #ccc; text-align: left; }
        .exp-del { background: none; border: 1px solid red; color: red; cursor: pointer; }
        #form-error { color: red; margin-top: 5px; }
        label { display: block; margin-bottom: 8px; }
        input[type="number"], select, textarea, input[type="date"] {
            width: 100%; box-sizing: border-box;
        }
    </style>
</head>
<body>
    <h1>Personal Expense Tracker</h1>

    <form id="expense-form">
        <label>Amount:
            <input type="number" id="amount" required>
        </label>
        <label>Category:
            <select id="category">
                <option value="groceries">Groceries</option>
                <option value="transport">Transport</option>
                <option value="bills">Bills</option>
                <option value="fun">Fun</option>
            </select>
        </label>
        <label>Date:
            <input type="date" id="date" required>
        </label>
        <label>Note (optional):
            <textarea id="note"></textarea>
        </label>
        <button type="submit" id="add-expense">Add Expense</button>
        <div id="form-error"></div>
    </form>

    <hr>

    <div>
        <label>Filter by category:
            <select id="filter-category">
                <option value="all">All</option>
                <option value="groceries">Groceries</option>
                <option value="transport">Transport</option>
                <option value="bills">Bills</option>
                <option value="fun">Fun</option>
            </select>
        </label>
        <label>From:
            <input type="date" id="filter-from">
        </label>
        <label>To:
            <input type="date" id="filter-to">
        </label>
    </div>

    <table id="expense-table">
        <thead>
            <tr>
                <th>Amount</th>
                <th>Category</th>
                <th>Date</th>
                <th></th>
            </tr>
        </thead>
        <tbody id="expense-list"></tbody>
    </table>

    <div id="total">Total: 0.00</div>
    <div id="category-totals"></div>

    <script>
        let expenses = JSON.parse(localStorage.getItem('expenses')) || [];

        function saveExpenses() {
            localStorage.setItem('expenses', JSON.stringify(expenses));
        }

        document.getElementById('expense-form').addEventListener('submit', function(e) {
            e.preventDefault();
            const amountInput = document.getElementById('amount');
            const amount = parseFloat(amountInput.value);
            const dateInput = document.getElementById('date');
            const date = dateInput.value;
            const categorySelect = document.getElementById('category');
            const noteArea = document.getElementById('note');

            let errorText = '';
            if (isNaN(amount) || amount <= 0) {
                errorText = 'Amount must be a positive number.';
            }
            if (!date) {
                errorText = 'Date is required.';
            }

            if (errorText) {
                document.getElementById('form-error').textContent = errorText;
                return;
            }

            const newExpense = { amount, category: categorySelect.value, date, note: noteArea.value };
            expenses.push(newExpense);
            saveExpenses();
            renderExpenses();

            amountInput.value = '';
            noteArea.value = '';
            document.getElementById('form-error').textContent = '';
        });

        function passesFilters(expense) {
            const catFilter = document.getElementById('filter-category').value;
            if (catFilter !== 'all' && expense.category !== catFilter) return false;

            const fromDate = document.getElementById('filter-from').value;
            const toDate = document.getElementById('filter-to').value;

            const expenseDate = new Date(expense.date);
            if (fromDate && expenseDate < new Date(fromDate)) return false;
            if (toDate && expenseDate > new Date(toDate)) return false;

            return true;
        }

        function renderExpenses() {
            const listContainer = document.getElementById('expense-list');
            listContainer.innerHTML = '';
            let visibleExpenses = [];

            for (let i = expenses.length - 1; i >= 0; i--) {
                const exp = expenses[i];
                if (!passesFilters(exp)) continue;
                visibleExpenses.push(exp);

                const row = document.createElement('tr');
                row.className = 'expense';

                const amountCell = document.createElement('td');
                amountCell.textContent = exp.amount.toFixed(2);
                row.appendChild(amountCell);

                const categoryCell = document.createElement('td');
                categoryCell.textContent = exp.category;
                row.appendChild(categoryCell);

                const dateCell = document.createElement('td');
                dateCell.textContent = new Date(exp.date).toLocaleDateString();
                row.appendChild(dateCell);

                const delBtn = document.createElement('button');
                delBtn.className = 'exp-del';
                delBtn.textContent = 'Delete';
                delBtn.onclick = () => {
                    expenses.splice(i, 1);
                    saveExpenses();
                    renderExpenses();
                };
                row.appendChild(delBtn);

                listContainer.appendChild(row);
            }

            const total = visibleExpenses.reduce((sum, exp) => sum + exp.amount, 0).toFixed(2);
            document.getElementById('total').textContent = `Total: ${total}`;

            const catTotals = {};
            visibleExpenses.forEach(exp => {
                if (!catTotals[exp.category]) {
                    catTotals[exp.category] = 0;
                }
                catTotals[exp.category] += exp.amount;
            });

            const catsContainer = document.getElementById('category-totals');
            catsContainer.innerHTML = '';
            for (const [cat, totalAmount] of Object.entries(catTotals)) {
                const el = document.createElement('div');
                el.className = 'cat-total';
                el.setAttribute('data-cat', cat);
                el.textContent = `${cat}: ${totalAmount.toFixed(2)}`;
                catsContainer.appendChild(el);
            }
        }

        document.getElementById('filter-category').addEventListener('change', renderExpenses);
        document.getElementById('filter-from').addEventListener('input', renderExpenses);
        document.getElementById('filter-to').addEventListener('input', renderExpenses);

        renderExpenses();
    </script>
</body>
</html>
